 const lacorruption = "{\"parsed\":{\"_path\":\"/fr/_archived/lacorruption\",\"_dir\":\"_archived\",\"_draft\":false,\"_partial\":true,\"_locale\":\"\",\"title\":\"La corruption vous mettra en retard : un (petit) exemple concret\",\"description\":\"Une expérience personnelle dans une banque africaine qui illustre comment la corruption et les passe-droits peuvent paradoxalement faire perdre du temps à ceux qui y participent. Un témoignage sur les pratiques quotidiennes de corruption.\",\"image\":\"/images/articles/corruption.jpg\",\"createdAt\":\"12-03-2025\",\"id\":11,\"keywords\":\"corruption Afrique, passe-droits, banque Afrique, Ecobank, pot-de-vin, file d'attente, corruption quotidienne, pratiques bancaires Afrique, corruption petite échelle, témoignage corruption\",\"summary\":\"Un récit personnel dans une agence bancaire en Afrique où l'auteur refuse de participer au système de corruption proposé par un agent de sécurité. L'histoire démontre comment ceux qui ont payé pour passer devant tout le monde se retrouvent finalement servis en dernier, illustrant que la corruption, loin de faire gagner du temps, met tout le monde en retard.\",\"og\":{\"title\":\"La corruption vous mettra en retard : un (petit) exemple concret\",\"description\":\"Une expérience vécue dans une banque africaine montre que la corruption ne fait pas gagner de temps, mais en fait perdre à tous. Un témoignage édifiant.\",\"image\":\"/images/articles/corruption.jpg\",\"url\":\"/fr/lacorruption\",\"type\":\"article\",\"site_name\":\"Jean-Luc Houédanou\",\"locale\":\"fr_FR\"},\"twitter\":{\"card\":\"summary_large_image\",\"title\":\"La corruption vous mettra en retard : un (petit) exemple concret\",\"description\":\"La corruption quotidienne dans les banques africaines : pourquoi elle fait perdre du temps à tout le monde. Un récit personnel et une leçon à retenir.\",\"image\":\"/images/articles/corruption.jpg\",\"creator\":\"@jeanluchouedanou\"},\"article\":{\"published_time\":\"2025-03-12T00:00:00Z\",\"modified_time\":\"2025-03-12T00:00:00Z\",\"author\":\"Jean-Luc Houédanou\",\"section\":\"Société\",\"tag\":[\"corruption Afrique\",\"passe-droits\",\"banque Afrique\",\"Ecobank\",\"pot-de-vin\",\"file d'attente\",\"corruption quotidienne\",\"pratiques bancaires Afrique\",\"corruption petite échelle\",\"témoignage corruption\"]},\"schema\":{\"type\":\"Article\",\"headline\":\"La corruption vous mettra en retard : un (petit) exemple concret\",\"description\":\"Une expérience personnelle dans une banque africaine qui illustre comment la corruption et les passe-droits peuvent paradoxalement faire perdre du temps à ceux qui y participent. Un témoignage sur les pratiques quotidiennes de corruption.\",\"image\":\"/images/articles/corruption.jpg\",\"datePublished\":\"2025-03-12\",\"dateModified\":\"2025-03-12\",\"author\":\"Jean-Luc Houédanou\",\"publisher\":\"Jean-Luc Houédanou\"},\"body\":{\"type\":\"root\",\"children\":[{\"type\":\"element\",\"tag\":\"h1\",\"props\":{\"id\":\"la-corruption-vous-mettra-en-retard-un-petit-exemple-concret\"},\"children\":[{\"type\":\"text\",\"value\":\"La corruption vous mettra en retard : un (petit) exemple concret\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Voici une situation qui pourrait sembler banale, mais elle reflète une réalité bien ancrée en Afrique, souvent ignorée ou simplement acceptée.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Il y a des endroits où je déteste aller.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Deux, en particulier :\"}]},{\"type\":\"element\",\"tag\":\"ul\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"🏥 \"},{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Les hôpitaux\"}]}]},{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"🏦 \"},{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Les banques\"}]}]}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Pourquoi ? C'est simple : les files d'attente interminables et ces petites manigances où certains, grâce à des passe-droits, tentent de griller tout le monde. Un jeu auquel je n'ai jamais voulu participer.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Mais parfois, on n'a pas le choix.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"En novembre dernier, me voilà contraint de me rendre au centre d'Ecobank à Aghien pour renouveler ma carte de guichet.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"À mon arrivée à 7h, le décor est planté : \"},{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"une longue file d'attente\"}]},{\"type\":\"text\",\"value\":\".\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Pas le choix, je prends mon mal en patience.\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"un-service-bien-rodé\"},\"children\":[{\"type\":\"text\",\"value\":\"Un \\\"service\\\" bien rodé\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Après 30 minutes d'attente, je suis interpellé par \"},{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"👮🏿‍♂️ \\\"le chef du service sécurité\\\"\"}]},{\"type\":\"text\",\"value\":\", qui s'approche et me lance d'un ton complice :\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"👮🏿‍♂️ \"},{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"\\\"Le boss... c'est comment ?\\\"\"}]},{\"type\":\"element\",\"tag\":\"br\",\"props\":{},\"children\":[]},{\"type\":\"text\",\"value\":\"\\n🧑🏿‍💼 \"},{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"\\\"Bonjour.\\\"\"}]},{\"type\":\"element\",\"tag\":\"br\",\"props\":{},\"children\":[]},{\"type\":\"text\",\"value\":\"\\n👮🏿‍♂️ \"},{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"\\\"Ah, boss, toi aussi, faut pas faire les choses comme ça.\\\"\"}]},{\"type\":\"element\",\"tag\":\"br\",\"props\":{},\"children\":[]},{\"type\":\"text\",\"value\":\"\\n🧑🏿‍💼 \"},{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"\\\"Ah ?\\\"\"}]},{\"type\":\"element\",\"tag\":\"br\",\"props\":{},\"children\":[]},{\"type\":\"text\",\"value\":\"\\n👮🏿‍♂️ \"},{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"\\\"Oui, ah... Quand tu viens comme ça, tu me vois, et on gère ça vite fait.\\\"\"}]},{\"type\":\"element\",\"tag\":\"br\",\"props\":{},\"children\":[]},{\"type\":\"text\",\"value\":\"\\n🧑🏿‍💼 \"},{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"\\\"J'ai compris.\\\"\"}]},{\"type\":\"text\",\"value\":\" (sur un ton sec… oui, ce matin-là, j'étais d'humeur massacrante et pas du tout disposé à jouer le jeu.)\"},{\"type\":\"element\",\"tag\":\"br\",\"props\":{},\"children\":[]},{\"type\":\"text\",\"value\":\"\\n👮🏿‍♂️ \"},{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"\\\"Ok, donc on gère après, non ?\\\"\"}]},{\"type\":\"element\",\"tag\":\"br\",\"props\":{},\"children\":[]},{\"type\":\"text\",\"value\":\"\\n🧑🏿‍💼 \"},{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"\\\"Je dis que j'ai compris.\\\"\"}]}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Surpris par ma réponse, il tourne les talons, l'air méprisant.\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"les-boss-dabord\"},\"children\":[{\"type\":\"text\",\"value\":\"Les \\\"boss\\\" d'abord\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Encore 30 minutes passent.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"La banque ouvre enfin. Qui entre en premier ? Les \"},{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"💼 \\\"boss\\\"\"}]},{\"type\":\"text\",\"value\":\", comprenez ceux qui ont glissé un billet au fameux chef.\"},{\"type\":\"element\",\"tag\":\"br\",\"props\":{},\"children\":[]},{\"type\":\"text\",\"value\":\"\\nQuant à nous, la plèbe, nous patientons encore. Heureusement, il faisait moins chaud que d'habitude, rendant l'attente plus supportable.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Trente minutes plus tard, c'est enfin mon tour.\"},{\"type\":\"element\",\"tag\":\"br\",\"props\":{},\"children\":[]},{\"type\":\"text\",\"value\":\"\\nMais pas sans sentir le regard pesant du chef de la sécurité.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Qu'importe... Je monte gaillardement au premier étage, \"},{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"guidé par un personnel d'une grande courtoisie\"}]},{\"type\":\"text\",\"value\":\" (il faut le souligner).\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"un-joli-coup-du-karma\"},\"children\":[{\"type\":\"text\",\"value\":\"Un joli coup du karma\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Arrivé à l'étage, je tombe pile poil sur une conversation savoureuse entre deux employés chargés des changements de cartes :\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"👨🏿‍💼 \"},{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"\\\"Bro... mais c'est qui, tous ces gens, samedi matin là ?\\\"\"}]},{\"type\":\"element\",\"tag\":\"br\",\"props\":{},\"children\":[]},{\"type\":\"text\",\"value\":\"\\n👩🏿‍💼 \"},{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"\\\"Ayi... C'est le même gars là qui les a fait monter.\\\"\"}]},{\"type\":\"element\",\"tag\":\"br\",\"props\":{},\"children\":[]},{\"type\":\"text\",\"value\":\"\\n👨🏿‍💼 \"},{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"\\\"Han... Celui qui pense qu'il est le chef de l'agence ? Attends, ceux-là vont passer en dernier.\\\"\"}]}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Et, surprise :\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"👩🏿‍💼 \"},{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"\\\"Venez, monsieur.\\\"\"}]},{\"type\":\"element\",\"tag\":\"br\",\"props\":{},\"children\":[]},{\"type\":\"text\",\"value\":\"\\n🧑🏿‍💼 😊\\n\"},{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"En 15 minutes, ma carte fut changée.\"}]},{\"type\":\"element\",\"tag\":\"br\",\"props\":{},\"children\":[]},{\"type\":\"text\",\"value\":\"\\nSous les regards furieux des \\\"boss\\\".\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"morale-de-lhistoire\"},\"children\":[{\"type\":\"text\",\"value\":\"Morale de l'histoire ?\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"La corruption ne vous fait pas gagner du temps.\"},{\"type\":\"element\",\"tag\":\"br\",\"props\":{},\"children\":[]},{\"type\":\"text\",\"value\":\"\\nAu contraire, \"},{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"elle vous met tous en retard.\"}]}]}],\"toc\":{\"title\":\"\",\"searchDepth\":2,\"depth\":2,\"links\":[{\"id\":\"un-service-bien-rodé\",\"depth\":2,\"text\":\"Un \\\"service\\\" bien rodé\"},{\"id\":\"les-boss-dabord\",\"depth\":2,\"text\":\"Les \\\"boss\\\" d'abord\"},{\"id\":\"un-joli-coup-du-karma\",\"depth\":2,\"text\":\"Un joli coup du karma\"},{\"id\":\"morale-de-lhistoire\",\"depth\":2,\"text\":\"Morale de l'histoire ?\"}]}},\"_type\":\"markdown\",\"_id\":\"content:fr:_archived:lacorruption.md\",\"_source\":\"content\",\"_file\":\"fr/_archived/lacorruption.md\",\"_stem\":\"fr/_archived/lacorruption\",\"_extension\":\"md\"},\"hash\":\"c2Nlczxh0I\"}";

